def gen(rng, size):
    n = max(1, size)
    bits = []
    while len(bits) < n - 1:
        if rng.random() < 0.5:
            bits.append(0)
        else:
            bits.append(1)
            bits.append(rng.randrange(0, 2))
    bits.append(0)
    return [bits]

