class Solution:
    def isOneBitCharacter(self, bits):
        n = len(bits)
        i = 0
        last_one = False
        while i < n:
            if bits[i] == 1:
                last_one = False
                i += 2
            else:
                last_one = True
                i += 1
        return last_one

solutions.python:
class Solution:
    def isOneBitCharacter(self, bits):
        i = 0
        n = len(bits)
        while i < n - 1:
            i += 2 if bits[i] == 1 else 1
        return i == n - 1

